import React from 'react';
import { AbsoluteFill } from 'remotion';

// Import our Lego Blocks
import { 
  MediaContainer, KineticText, GenerativeBackground, DynamicPath, 
  ScreenMarker, MockupFrame, AvatarBubble, ProgressIndicator, 
  VectorShape, LottieSticker 
} from './VisualElements';
import { DynamicLottie } from './DynamicLottie';
import { UserVideo } from './UserVideo';
import { MotionPrimitive, MotionType } from './MotionPrimitives';
import { StyleModifier, ModifierType } from './StyleModifiers';
import { LayoutEngine, LayoutType } from './LayoutEngines';

// ==========================================
// 1. THE JSON SCHEMA (What the AI will output)
// ==========================================
export interface DynamicNode {
  visual?: { type: string; [key: string]: any }; // The core element
  layout?: { type: LayoutType; [key: string]: any; children: DynamicNode[] }; // A container for other elements
  modifier?: { type: ModifierType; [key: string]: any }; // CSS Polish
  motion?: { type: MotionType; [key: string]: any }; // Animations
}

export interface DynamicSceneProps {
  backgroundColor?: string;
  nodes: DynamicNode[]; // The root array of elements to render
}

// ==========================================
// 2. THE RECURSIVE RENDERER
// ==========================================
const RenderNode: React.FC<{ node: DynamicNode; index?: number }> = ({ node, index = 0 }) => {
  let innerContent: React.ReactNode = null;

  // STEP A: Is this a Layout Container or a pure Visual?
  if (node.layout) {
    const { type, children, ...layoutProps } = node.layout;
    innerContent = (
      <LayoutEngine type={type as LayoutType} {...layoutProps}>
        {children.map((child, i) => (
          <RenderNode key={i} node={child} index={i} />
        ))}
      </LayoutEngine>
    );
  } else if (node.visual) {
    const { type, ...props } = node.visual;
    // Map the JSON string to the actual React Component
    switch (type) {
      case 'MediaContainer': innerContent = <MediaContainer {...props as any} />; break;
      case 'KineticText': innerContent = <KineticText {...props as any} />; break;
      case 'GenerativeBackground': innerContent = <GenerativeBackground {...props as any} />; break;
      case 'DynamicPath': innerContent = <DynamicPath {...props as any} />; break;
      case 'ScreenMarker': innerContent = <ScreenMarker {...props as any} />; break;
      case 'MockupFrame': innerContent = <MockupFrame {...props as any} />; break;
      case 'AvatarBubble': innerContent = <AvatarBubble {...props as any} />; break;
      case 'ProgressIndicator': innerContent = <ProgressIndicator {...props as any} />; break;
      case 'VectorShape': innerContent = <VectorShape {...props as any} />; break;
      case 'LottieSticker': innerContent = <LottieSticker {...props as any} />; break;
      case 'Lottie': innerContent = <DynamicLottie url={props.url} />; break;
      case 'UserVideo': innerContent = <UserVideo url={props.url} />; break;
      default: innerContent = <div style={{ color: 'red' }}>Unknown Visual: {type}</div>;
    }
  }

  if (!innerContent) return null;

  // STEP B: Does it need a CSS Modifier (Like Glassmorphism or Neon?)
  if (node.modifier) {
    const { type, ...modProps } = node.modifier;
    innerContent = (
      <StyleModifier type={type as ModifierType} {...modProps}>
        {innerContent}
      </StyleModifier>
    );
  }

  // STEP C: Does it need Animation? (Wrap it in Motion Primitive)
  if (node.motion) {
    const { type, ...motionProps } = node.motion;
    innerContent = (
      <MotionPrimitive type={type as MotionType} {...motionProps}>
        {innerContent}
      </MotionPrimitive>
    );
  }

  return <>{innerContent}</>;
};

// ==========================================
// 3. THE MASTER EXPORT
// ==========================================
export const DynamicSceneRenderer: React.FC<DynamicSceneProps> = ({ backgroundColor = '#000000', nodes = [] }) => {
  return (
    <AbsoluteFill style={{ backgroundColor, overflow: 'hidden' }}>
      {nodes.map((node, i) => (
        <RenderNode key={i} node={node} index={i} />
      ))}
    </AbsoluteFill>
  );
};
